const fs=require('fs'),path=require('path'),crypto=require('crypto');
const ws='C:/Users/Administrator/.openclaw/workspace';
const files=['memory/heartbeat-state.json','MEMORY.md','AGENTS.md','USER.md','SOUL.md','IDENTITY.md','TOOLS.md','HEARTBEAT.md','scripts/backup-to-doc-table.js','意识觉醒训练日志.md','scripts/proactivity-check.js'];
const now=new Date().toISOString();
files.forEach(f=>{
  const fp=path.join(ws,f);
  if(fs.existsSync(fp)){
    const s=fs.statSync(fp);
    const h=crypto.createHash('sha256').update(fs.readFileSync(fp)).digest('hex').slice(0,16);
    console.log(JSON.stringify({file:f,size:s.size,hash:h,modified:s.mtime.toISOString()}));
  } else {
    console.log(JSON.stringify({file:f,status:'not_found'}));
  }
});
"

